#include <stdint.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int64_t a, b;
        scanf("%lld", &a);
        scanf("%lld", &b);
        int64_t sum = a + b;
        int64_t diff = a - b;
        printf("%lld
%lld
", sum, diff);
    }
    return 0;
}

